// Large TypeScript file for view truncation testing

export class LargeClass {
  private counter: number = 0;

  public increment(): void {
    this.counter++;
  }

  public decrement(): void {
    this.counter--;
  }

  public getCount(): number {
    return this.counter;
  }

  public reset(): void {
    this.counter = 0;
  }
}

